package com.example.mbptodabookingapp.data.api
import android.content.Context import com.example.mbptodabookingapp.data.local.PrefsManager import com.example.mbptodabookingapp.utils.Constants import okhttp3.Interceptor import okhttp3.OkHttpClient import okhttp3.logging.HttpLoggingInterceptor import retrofit2.Retrofit import retrofit2.converter.gson.GsonConverterFactory
/** * Singleton Retrofit client. * * Must call [ApiClient.init] once from your Application class before any API call. * * Features: * - Automatically attaches "Authorization: Bearer <token>" to every request. * - Clears SharedPreferences on 401 so the user must log in again. * - Logs all HTTP traffic in DEBUG (remove HttpLoggingInterceptor in production). * * See: docs/flows/ANDROID_SETUP.md → ApiClient * See: docs/flows/AUTH_FLOW.md → Authenticated Request Flow */ object ApiClient {
private lateinit var appContext: Context
/** * Call once in your Application.onCreate(). * Stores the application context so the interceptor can read the JWT token. */ fun init(context: Context) { appContext = context.applicationContext }
// ── Interceptors ──────────────────────────────────────────────────────────
/** * Reads the JWT token from SharedPreferences and injects it as a Bearer header. * On a 401 response, clears all stored credentials — the resulting HttpException * will propagate up through the Repository → ViewModel → Activity/Fragment, * which should then navigate the user back to LoginActivity. * * See: docs/flows/AUTH_FLOW.md → Token Expiry & Refresh */ private val authInterceptor = Interceptor { chain -> val token = PrefsManager.getJwtToken(appContext) val request = chain.request().newBuilder() .apply { if (token != null) addHeader("Authorization", "Bearer $token") } .build()
val response = chain.proceed(request)
if (response.code == 401) { // Token expired or invalid — wipe local session. // The 401 HttpException will propagate to the ViewModel to trigger logout UI. PrefsManager.clearAll(appContext) }
response }
/** Logs full request + response bodies. Set to NONE before releasing to production. */ private val loggingInterceptor = HttpLoggingInterceptor().apply { level = HttpLoggingInterceptor.Level.BODY }
// ── OkHttp + Retrofit ─────────────────────────────────────────────────────
private val okHttpClient by lazy { OkHttpClient.Builder() .addInterceptor(authInterceptor) .addInterceptor(loggingInterceptor) .build() }
/** * The single Retrofit-generated [ApiService] instance. * Access all API calls via: ApiClient.instance.login(...), etc. */ val instance: ApiService by lazy { Retrofit.Builder() .baseUrl(Constants.BASE_URL) .client(okHttpClient) .addConverterFactory(GsonConverterFactory.create()) .build() .create(ApiService::class.java) } }

package com.example.mbptodabookingapp.data.api

import com.example.mbptodabookingapp.data.models.AdminUser
import com.example.mbptodabookingapp.data.models.Booking
import com.example.mbptodabookingapp.data.models.BookingRequest
import com.example.mbptodabookingapp.data.models.CreateBookingResponse
import com.example.mbptodabookingapp.data.models.FcmTokenRequest
import com.example.mbptodabookingapp.data.models.LoginRequest
import com.example.mbptodabookingapp.data.models.LoginResponse
import com.example.mbptodabookingapp.data.models.PendingDriver
import com.example.mbptodabookingapp.data.models.RegisterRequest
import com.example.mbptodabookingapp.data.models.UpdateLocationRequest
import retrofit2.http.Body
import retrofit2.http.DELETE
import retrofit2.http.GET
import retrofit2.http.POST
import retrofit2.http.PUT
import retrofit2.http.Path

/**
 * Retrofit interface — defines every API endpoint.
 * All methods are suspend functions called from within a coroutine (ViewModel/Repository).
 *
 * See: docs/flows/ANDROID_SETUP.md → ApiService
 * See: docs/INDEX.md → All Endpoints at a Glance
 */
interface ApiService {

    // ── Auth ──────────────────────────────────────────────────────────────────
    // See: docs/api/AUTH.md

    @POST("auth/register")
    suspend fun register(
        @Body body: RegisterRequest
    ): ApiResponse<Map<String, Int>>

    @POST("auth/login")
    suspend fun login(
        @Body body: LoginRequest
    ): ApiResponse<LoginResponse>

    // ── Bookings ──────────────────────────────────────────────────────────────
    // See: docs/api/BOOKINGS.md

    /** Create a new ride request. Role: passenger */
    @POST("bookings")
    suspend fun createBooking(
        @Body body: BookingRequest
    ): ApiResponse<CreateBookingResponse>

    /** List bookings — response is role-filtered by the API (passenger/driver/admin). */
    @GET("bookings")
    suspend fun getBookings(): ApiResponse<List<Booking>>

    /** Get a single booking by ID. */
    @GET("bookings/{id}")
    suspend fun getBookingById(
        @Path("id") id: Int
    ): ApiResponse<Booking>

    /** Passenger ride history. Role: passenger */
    @GET("passenger/history")
    suspend fun getPassengerHistory(): ApiResponse<List<Booking>>

    // ── Driver ────────────────────────────────────────────────────────────────
    // See: docs/api/DRIVER.md

    /** Get all pending (unassigned) booking requests. Role: driver */
    @GET("driver/requests")
    suspend fun getDriverRequests(): ApiResponse<List<Booking>>

    /** Accept a pending booking. Role: driver */
    @POST("driver/accept/{booking_id}")
    suspend fun acceptRide(
        @Path("booking_id") bookingId: Int
    ): ApiResponse<Unit>

    /** Reject a pending booking. Role: driver */
    @POST("driver/reject/{booking_id}")
    suspend fun rejectRide(
        @Path("booking_id") bookingId: Int
    ): ApiResponse<Unit>

    /** Mark an accepted/in-progress ride as completed. Role: driver */
    @POST("driver/complete/{booking_id}")
    suspend fun completeRide(
        @Path("booking_id") bookingId: Int
    ): ApiResponse<Unit>

    /** Update driver's current GPS coordinates. Role: driver */
    @PUT("driver/location")
    suspend fun updateLocation(
        @Body body: UpdateLocationRequest
    ): ApiResponse<Unit>

    // ── FCM ───────────────────────────────────────────────────────────────────
    // See: docs/api/FCM.md

    /** Register or refresh the FCM device token for the current user. Role: any */
    @PUT("user/fcm-token")
    suspend fun updateFcmToken(
        @Body body: FcmTokenRequest
    ): ApiResponse<Unit>

    // ── Admin ─────────────────────────────────────────────────────────────────
    // See: docs/api/ADMIN.md

    /** List all registered users. Role: admin */
    @GET("admin/users")
    suspend fun getAllUsers(): ApiResponse<List<AdminUser>>

    /** List drivers with approval_status = 'pending'. Role: admin */
    @GET("admin/drivers/pending")
    suspend fun getPendingDrivers(): ApiResponse<List<PendingDriver>>

    /** List all bookings in the system. Role: admin */
    @GET("admin/bookings")
    suspend fun getAllBookings(): ApiResponse<List<Booking>>

    /** Approve a pending driver account. Role: admin */
    @PUT("admin/driver/approve/{id}")
    suspend fun approveDriver(
        @Path("id") driverId: Int
    ): ApiResponse<Unit>

    /** Reject a pending driver account. Role: admin */
    @PUT("admin/driver/reject/{id}")
    suspend fun rejectDriver(
        @Path("id") driverId: Int
    ): ApiResponse<Unit>

    /** Re-activate a deactivated user. Role: admin */
    @PUT("admin/user/activate/{id}")
    suspend fun activateUser(
        @Path("id") userId: Int
    ): ApiResponse<Unit>

    /** Deactivate a user account. Role: admin */
    @PUT("admin/user/deactivate/{id}")
    suspend fun deactivateUser(
        @Path("id") userId: Int
    ): ApiResponse<Unit>

    /** Permanently delete a user and all related records. Role: admin */
    @DELETE("admin/user/{id}")
    suspend fun deleteUser(
        @Path("id") userId: Int
    ): ApiResponse<Unit>
}

package com.example.mbptodabookingapp.data.local

import android.content.Context
import androidx.core.content.edit
import com.example.mbptodabookingapp.data.models.LoggedInUser

/**
 * Manages all SharedPreferences storage for the app.
 * Stores JWT token, user info, and FCM device token.
 *
 * See: docs/models/USER.md → SharedPreferences Storage
 *
 * Usage:
 *   PrefsManager.saveLoginData(context, token, user)
 *   PrefsManager.getJwtToken(context)
 *   PrefsManager.clearAll(context)  // on logout or 401
 */
object PrefsManager {

    private const val PREFS_NAME   = "ptoda_prefs"
    private const val KEY_TOKEN    = "jwt_token"
    private const val KEY_USER_ID  = "user_id"
    private const val KEY_ROLE     = "user_role"
    private const val KEY_NAME     = "user_name"
    private const val KEY_FCM      = "fcm_token"

    // ── Login / Logout ────────────────────────────────────────────────────────

    /**
     * Persist JWT token and user info after a successful login.
     * Call this immediately after POST /auth/login succeeds.
     */
    fun saveLoginData(context: Context, token: String, user: LoggedInUser) {
        context.getSharedPreferences(PREFS_NAME, Context.MODE_PRIVATE).edit {
            putString(KEY_TOKEN,  token)
            putInt(KEY_USER_ID,   user.id)
            putString(KEY_ROLE,   user.role)
            putString(KEY_NAME,   user.name)
        }
    }

    /** Clear all stored data — call on logout or when a 401 is received. */
    fun clearAll(context: Context) {
        context.getSharedPreferences(PREFS_NAME, Context.MODE_PRIVATE).edit { clear() }
    }

    // ── Getters ───────────────────────────────────────────────────────────────

    /** Returns the stored JWT token, or null if the user is not logged in. */
    fun getJwtToken(context: Context): String? =
        context.getSharedPreferences(PREFS_NAME, Context.MODE_PRIVATE)
            .getString(KEY_TOKEN, null)

    /** Returns the stored user role ("passenger" | "driver" | "admin"), or null. */
    fun getUserRole(context: Context): String? =
        context.getSharedPreferences(PREFS_NAME, Context.MODE_PRIVATE)
            .getString(KEY_ROLE, null)

    /** Returns the stored user ID, or -1 if not logged in. */
    fun getUserId(context: Context): Int =
        context.getSharedPreferences(PREFS_NAME, Context.MODE_PRIVATE)
            .getInt(KEY_USER_ID, -1)

    /** Returns the stored display name, or null. */
    fun getUserName(context: Context): String? =
        context.getSharedPreferences(PREFS_NAME, Context.MODE_PRIVATE)
            .getString(KEY_NAME, null)

    /** Returns true if a JWT token exists (user is logged in). */
    fun isLoggedIn(context: Context): Boolean = getJwtToken(context) != null

    // ── FCM Token ─────────────────────────────────────────────────────────────

    /**
     * Save FCM device token locally.
     * Called from PTODAFirebaseMessagingService.onNewToken().
     * See: docs/api/FCM.md
     */
    fun saveFcmToken(context: Context, token: String) {
        context.getSharedPreferences(PREFS_NAME, Context.MODE_PRIVATE).edit {
            putString(KEY_FCM, token)
        }
    }

    /** Returns the locally saved FCM token, or null if not yet received. */
    fun getFcmToken(context: Context): String? =
        context.getSharedPreferences(PREFS_NAME, Context.MODE_PRIVATE)
            .getString(KEY_FCM, null)
}

package com.example.mbptodabookingapp.data.models
/** * Models for admin-specific endpoints. * See: docs/api/ADMIN.md */
/** Full user row returned by GET /admin/users */ data class AdminUser( val id: Int, val name: String, val email: String, val role: String, // "passenger" | "driver" | "admin" val status: String, // "active" | "inactive" val created_at: String )
/** Driver row returned by GET /admin/drivers/pending */ data class PendingDriver( val id: Int, // users.id (not driver_info.id) val name: String, val email: String, val created_at: String, val license_no: String?, val vehicle_no: String?, val approval_status: String // always "pending" in this list )

package com.example.mbptodabookingapp.data.models
/** * Booking request and response models. * See: docs/models/BOOKING.md · docs/api/BOOKINGS.md * * Status lifecycle: * requested → accepted → in_progress → completed * ↘ rejected * requested ↘ cancelled (future) */
data class BookingRequest( val pickup_address: String, val pickup_lat: Double, val pickup_lng: Double, val dropoff_address: String, val dropoff_lat: Double, val dropoff_lng: Double )
data class Booking( val id: Int, val passenger_id: Int, val driver_id: Int?, // null until a driver accepts val pickup_address: String, val pickup_lat: String, // returned as String from MySQL DECIMAL val pickup_lng: String, val dropoff_address: String, val dropoff_lat: String, val dropoff_lng: String, val status: String, // see BookingStatus constants in Constants.kt val created_at: String, val updated_at: String? ) { /** Convenience: parse lat/lng strings to Double for Google Maps use. */ fun pickupLatLng() = Pair(pickup_lat.toDouble(), pickup_lng.toDouble()) fun dropoffLatLng() = Pair(dropoff_lat.toDouble(), dropoff_lng.toDouble()) }
data class CreateBookingResponse( val booking_id: Int )

package com.example.mbptodabookingapp.data.models
/** * Models for driver-specific endpoints. * See: docs/api/DRIVER.md · docs/models/DRIVER_INFO.md */
/** Request body for PUT /driver/location */ data class UpdateLocationRequest( val lat: Double, val lng: Double )
/** * Driver GPS position — used when displaying driver on the map. * See: docs/models/DRIVER_INFO.md */ data class DriverLocation( val user_id: Int, val current_lat: Double?, val current_lng: Double? )

package com.example.mbptodabookingapp.data.models
/** * User returned in login response and admin user lists. * NOTE: Password is never included in any API response. * See: docs/models/USER.md */ data class User( val id: Int, val name: String, val email: String, val role: String, // "passenger" | "driver" | "admin" val status: String, // "active" | "inactive" val created_at: String )
/** * Compact user info embedded inside LoginResponse and stored in SharedPreferences. * See: docs/models/USER.md · docs/api/AUTH.md */ data class LoggedInUser( val id: Int, val name: String, val email: String, val role: String, // "passenger" | "driver" | "admin" val status: String // "active" | "inactive" )

package com.example.mbptodabookingapp.utils

/**
 * API base URL constants.
 * Switch BASE_URL to the appropriate value depending on your setup.
 * See: docs/INDEX.md → API Base URL table
 */
object Constants {
    // Android Emulator → XAMPP Apache
    const val BASE_URL_EMULATOR = "http://10.0.2.2/ptoda_booking_api/"

    // Android Emulator → PHP built-in dev server (php -S localhost:8001)
    const val BASE_URL_DEV_SRV  = "http://10.0.2.2:8001/"

    // Physical device on same Wi-Fi → XAMPP Apache (replace with your PC's local IP)
    const val BASE_URL_DEVICE   = "http://192.168.1.x/ptoda_booking_api/"

    // Active base URL used by ApiClient — change this line to switch environments
    const val BASE_URL = BASE_URL_EMULATOR
}

/**
 * User role values — must match the PHP API's ENUM('passenger','driver','admin')
 * See: docs/models/USER.md
 */
object UserRole {
    const val PASSENGER = "passenger"
    const val DRIVER    = "driver"
    const val ADMIN     = "admin"
}

/**
 * User account status values — must match users.status ENUM
 * See: docs/models/USER.md
 */
object UserStatus {
    const val ACTIVE   = "active"
    const val INACTIVE = "inactive"
}

/**
 * Driver approval status values — must match driver_info.approval_status ENUM
 * See: docs/models/DRIVER_INFO.md
 */
object DriverApprovalStatus {
    const val PENDING  = "pending"
    const val APPROVED = "approved"
    const val REJECTED = "rejected"
}

/**
 * Booking status values — must match bookings.status ENUM
 * See: docs/models/BOOKING.md
 *
 * Lifecycle:
 *   requested → accepted → in_progress → completed
 *                       ↘ rejected
 *   requested ↘ cancelled  (future)
 */
object BookingStatus {
    const val REQUESTED   = "requested"
    const val ACCEPTED    = "accepted"
    const val IN_PROGRESS = "in_progress"
    const val COMPLETED   = "completed"
    const val CANCELLED   = "cancelled"
    const val REJECTED    = "rejected"

    /** Returns true if the booking has reached a terminal state (no further updates expected). */
    fun isTerminal(status: String): Boolean =
        status == COMPLETED || status == CANCELLED || status == REJECTED
}

